// ===============================
// src/pages/Home.js
// ===============================
import React, { useEffect, useState } from "react";
import FileUpload from "../components/FileUpload";
import ResultCard from "../components/ResultCard";
import Loader from "../components/Loader";
import { checkHealth, processCheque } from "../services/api";

function Home() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [health, setHealth] = useState("Checking...");

  useEffect(() => {
    checkHealth()
      .then(() => setHealth("Backend is running"))
      .catch(() => setHealth("Backend not reachable"));
  }, []);

  const handleSubmit = async () => {
    if (!file) {
      alert("Please upload a cheque image");
      return;
    }

    setLoading(true);
    try {
      const data = await processCheque(file);
      setResult(data);
    } catch (err) {
      console.error(err);
      alert("Error processing cheque");
    }
    setLoading(false);
  };

  return (
    <div style={{ padding: "30px", fontFamily: "Arial" }}>
      <h1>RailSeva Cheque Intelligence</h1>

      <p><b>Status:</b> {health}</p>

      <FileUpload setFile={setFile} />

      <br /><br />

      <button onClick={handleSubmit}>Process Cheque</button>

      {loading && <Loader />}

      <ResultCard result={result} />
    </div>
  );
}

export default Home;
